import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../components/ui/card';
import { Button } from '../components/ui/button';
import { Badge } from '../components/ui/badge';
import { Input } from '../components/ui/input';
import { Calendar, Users, FileText, Clock, Stethoscope, ChevronRight, Search } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';
import { getDashboardStats, getTodayAppointments } from '../services/mockData';
import LoadingSpinner from '../components/ui/LoadingSpinner';
import UniversalSearch from '../features/search/UniversalSearch';

export default function DoctorDashboard() {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [stats, setStats] = useState(null);
  const [todayAppointments, setTodayAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showSearch, setShowSearch] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  useEffect(() => {
    const loadDashboardData = async () => {
      try {
        setLoading(true);
        const doctorId = user?.id || 'doc-1'; // Fallback for demo
        console.log('🩺 DoctorDashboard: Loading data for doctorId:', doctorId);
        console.log('👤 Current user:', user);
        
        const [dashboardStats, appointments] = await Promise.all([
          getDashboardStats(doctorId),
          getTodayAppointments(doctorId)
        ]);
        
        console.log('📊 Dashboard stats received:', dashboardStats);
        console.log('📅 Today appointments received:', appointments);
        
        setStats(dashboardStats);
        setTodayAppointments(appointments.slice(0, 3)); // Show only first 3 in preview
      } catch (error) {
        console.error('Error loading dashboard data:', error);
      } finally {
        setLoading(false);
      }
    };

    loadDashboardData();
  }, [user]);

  const handleCardClick = (cardType) => {
    const routes = {
      'today-appointments': `/app/doctor/today-appointments`,
      'active-patients': `/app/doctor/active-patients`,
      'pending-reviews': `/app/doctor/pending-reviews`,
      'availability': `/app/doctor/availability`
    };
    
    navigate(routes[cardType]);
  };

  const formatTime = (time) => {
    if (!time) return 'Time TBD';
    const [hours, minutes] = time.split(':');
    const hour = parseInt(hours);
    const ampm = hour >= 12 ? 'PM' : 'AM';
    const displayHour = hour % 12 || 12;
    return `${displayHour}:${minutes} ${ampm}`;
  };

  const handleSearchClick = () => {
    setShowSearch(true);
  };

  const handleSearchChange = (e) => {
    setSearchQuery(e.target.value);
  };

  const handleSearchKeyDown = (e) => {
    if (e.key === 'Enter') {
      setShowSearch(true);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-96">
        <LoadingSpinner size="lg" text="Loading dashboard..." />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Welcome Header */}
      <div className="bg-gradient-to-r from-green-500 to-blue-500 text-white rounded-lg p-6 shadow-lg">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h1 className="text-3xl font-bold mb-2">Good morning, {user?.name || 'Doctor'}!</h1>
            <p className="text-green-100">
              You have {stats?.todayAppointmentsCount || 0} appointments scheduled for today.
            </p>
          </div>
          
          {/* Dashboard Search Bar
          <div className="hidden sm:block">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-white/60 w-4 h-4" />
              <Input
                type="text"
                placeholder="Search your patients..."
                value={searchQuery}
                onChange={handleSearchChange}
                onKeyDown={handleSearchKeyDown}
                onClick={handleSearchClick}
                className="pl-10 pr-4 py-2 w-64 bg-white/20 border border-white/30 text-white placeholder:text-white/70 focus:bg-white/30 focus:border-white/50 transition-all duration-200 hover:bg-white/25"
              />
            </div>
          </div> */}
        </div>
      </div>

      {/* Clickable Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {/* Today's Appointments Card */}
        <Card 
          className="cursor-pointer hover:shadow-lg transform hover:-translate-y-1 transition-all duration-200 border-2 hover:border-blue-300 group"
          onClick={() => handleCardClick('today-appointments')}
        >
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-gray-600 group-hover:text-blue-600 transition-colors">
                  Today's Appointments
                </p>
                <p className="text-2xl font-semibold text-gray-900 mt-1">
                  {stats?.todayAppointmentsCount || 0}
                </p>
              </div>
              <div className="flex items-center gap-2">
                <Calendar className="h-8 w-8 text-blue-600 group-hover:text-blue-700 transition-colors" />
                <ChevronRight className="h-4 w-4 text-gray-400 group-hover:text-blue-600 transition-colors" />
              </div>
            </div>
          </CardContent>
        </Card>
        
        {/* Active Patients Card */}
        <Card 
          className="cursor-pointer hover:shadow-lg transform hover:-translate-y-1 transition-all duration-200 border-2 hover:border-green-300 group"
          onClick={() => handleCardClick('active-patients')}
        >
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-gray-600 group-hover:text-green-600 transition-colors">
                  Active Patients
                </p>
                <p className="text-2xl font-semibold text-gray-900 mt-1">
                  {stats?.activePatientsCount || 0}
                </p>
              </div>
              <div className="flex items-center gap-2">
                <Users className="h-8 w-8 text-green-600 group-hover:text-green-700 transition-colors" />
                <ChevronRight className="h-4 w-4 text-gray-400 group-hover:text-green-600 transition-colors" />
              </div>
            </div>
          </CardContent>
        </Card>
        
        {/* Pending Reviews Card */}
        <Card 
          className="cursor-pointer hover:shadow-lg transform hover:-translate-y-1 transition-all duration-200 border-2 hover:border-orange-300 group"
          onClick={() => handleCardClick('pending-reviews')}
        >
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-gray-600 group-hover:text-orange-600 transition-colors">
                  Pending Reviews
                </p>
                <p className="text-2xl font-semibold text-gray-900 mt-1">
                  {stats?.pendingReviewsCount || 0}
                </p>
              </div>
              <div className="flex items-center gap-2">
                <FileText className="h-8 w-8 text-orange-600 group-hover:text-orange-700 transition-colors" />
                <ChevronRight className="h-4 w-4 text-gray-400 group-hover:text-orange-600 transition-colors" />
              </div>
            </div>
          </CardContent>
        </Card>
        
        {/* Available Hours Card */}
        <Card 
          className="cursor-pointer hover:shadow-lg transform hover:-translate-y-1 transition-all duration-200 border-2 hover:border-purple-300 group"
          onClick={() => handleCardClick('availability')}
        >
          <CardContent className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-gray-600 group-hover:text-purple-600 transition-colors">
                  Available Hours
                </p>
                <p className="text-2xl font-semibold text-gray-900 mt-1">
                  {stats?.availableHoursToday || 0}h
                </p>
              </div>
              <div className="flex items-center gap-2">
                <Clock className="h-8 w-8 text-purple-600 group-hover:text-purple-700 transition-colors" />
                <ChevronRight className="h-4 w-4 text-gray-400 group-hover:text-purple-600 transition-colors" />
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Today's Schedule Preview */}
      <Card className="shadow-lg">
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="flex items-center gap-2">
                <Stethoscope className="w-5 h-5" />
                Today's Schedule Preview
              </CardTitle>
              <CardDescription>
                Your next few appointments for today
              </CardDescription>
            </div>
            <Button 
              variant="outline" 
              onClick={() => handleCardClick('today-appointments')}
              className="hover:bg-blue-50 hover:border-blue-300"
            >
              View All
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {todayAppointments.length === 0 ? (
            <div className="text-center py-8 text-gray-500">
              <Calendar className="w-12 h-12 mx-auto mb-4 text-gray-300" />
              <p>No appointments scheduled for today</p>
            </div>
          ) : (
            <div className="space-y-4">
              {todayAppointments.map((appointment) => (
                <div key={appointment.id} className="flex items-center justify-between p-4 border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors">
                  <div className="flex items-center gap-3">
                    <div className="text-sm font-medium text-blue-600 min-w-20">
                      {formatTime(appointment.time)}
                    </div>
                    <div>
                      <h4 className="font-medium">{appointment.patientName}</h4>
                      <p className="text-sm text-gray-500">{appointment.appointmentType}</p>
                    </div>
                  </div>
                  <Badge 
                    variant={appointment.status === 'confirmed' ? 'default' : 'secondary'}
                    className={appointment.status === 'confirmed' ? 'bg-green-100 text-green-800' : ''}
                  >
                    {appointment.status}
                  </Badge>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
      
      {/* Universal Search Modal */}
      {showSearch && (
        <UniversalSearch 
          onClose={() => {
            setShowSearch(false);
            setSearchQuery('');
          }}
          initialQuery={searchQuery}
        />
      )}
    </div>
  );
}
